 } } \right]\left[ {\matrix{
   i &amp; { - i}  \cr 
   { - i} &amp; i  \cr 

 } } \right] = \left[ {\matrix{
   { - 2} &amp; 2  \cr 
   2 &amp; { - 2}  \cr 

 } } \right] = 2\left[ {\matrix{
